INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Access control lists (ACLs)$q$, $q$Fine-grained rules evaluated at each stage of an SMTP conversation decide whether to accept, reject, or defer a message, enabling detailed anti-spam and anti-abuse policy.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Routers and transports$q$, $q$A modular pipeline of routers (deciding how an address should be handled) and transports (defining how delivery actually happens) gives administrators precise control over mail flow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$String expansion language$q$, $q$A compact, condition-aware templating syntax embedded throughout the configuration file lets policy and routing logic be written declaratively without external scripts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Content scanning framework$q$, $q$Built-in hooks make it straightforward to integrate third-party antivirus and antispam engines such as ClamAV and SpamAssassin directly into the mail pipeline.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$TLS and modern auth support$q$, $q$Native support for TLS encryption, SMTP AUTH, DKIM, DMARC, ARC, and DANE helps deployments meet current email authentication and transport-security expectations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$PCRE-based regex matching$q$, $q$Exim uses the PCRE2 (Perl Compatible Regular Expressions) library, originally created by its own author, for powerful pattern matching throughout routing and filtering rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$local_scan() and Perl extensibility$q$, $q$A C-level local_scan() API and optional embedded Perl interpreter allow administrators to add custom scanning or routing logic beyond the standard configuration language.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Cross-platform Unix deployment$q$, $q$Runs natively across Unix-like systems including Linux and BSD variants, with a Cygwin-based port available for Microsoft Windows environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Completely free under the GPL with no paid tiers, licensing fees, or vendor lock-in.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Extremely configurable ACL and routing system that supports very granular, per-domain mail policy, which is why it underpins large multi-tenant hosting platforms.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Long track record and huge installed base, including being the default MTA on Debian and the mailer bundled with cPanel/WHM.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Actively maintained on GitHub by an experienced volunteer team with regular security and feature releases.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Has a notable history of serious security vulnerabilities, including remote-code-execution flaws, that require diligent and timely patching.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Lacks a central queue manager, which its own documentation admits can hurt performance under very large mail queues compared to Postfix.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Configuration syntax and string-expansion language have a steep learning curve for administrators new to Exim.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$No official vendor or paid support contract exists; commercial help must come from third-party consultancies.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$What is Exim?$q$, $q$Exim is a free, open-source mail transfer agent (MTA) that routes and delivers email on Unix-like systems. It was created in 1995 by Philip Hazel at the University of Cambridge and is licensed under the GNU General Public License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Is Exim free to use?$q$, $q$Yes. Exim has always been free under the GPL-2.0-or-later license, with no paid editions, subscription tiers, or usage fees. Anyone can download, modify, and redistribute it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Who maintains Exim today?$q$, $q$Philip Hazel retired from Cambridge in 2007, and maintenance passed to a volunteer group known as the Exim Maintainers, including contributors such as Heiko Schlittermann and Jeremy Harris, who coordinate development on GitHub and via public mailing lists.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$How does Exim compare to Postfix?$q$, $q$Both are free, GPL-licensed MTAs, but Postfix uses a modular multi-process queue manager that generally handles very large queues more gracefully, while Exim offers a more flexible single-binary configuration language favored by hosting control panels for granular, per-domain policy.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Why is Exim so widely used in web hosting?$q$, $q$Exim ships as the default mail server in cPanel/WHM, one of the most widely deployed hosting control panels, and is also the default MTA on Debian Linux, which together give it one of the largest installed bases of any MTA on the public internet.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Has Exim had major security vulnerabilities?$q$, $q$Yes. Notable examples include CVE-2019-10149, a remote-code-execution flaw actively exploited by a Linux worm in 2019, and the '21Nails' cluster of vulnerabilities disclosed in 2021, making prompt patching important for any Exim deployment.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Shared web hosting mail infrastructure$q$, $q$Hosting providers running cPanel/WHM rely on Exim as the built-in MTA that handles mail sending and receiving for large numbers of customer domains on a single shared server.$q$, $q$Web hosting companies and system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Distribution-default server mail relay$q$, $q$Because Exim is the default MTA on Debian Linux and several derivatives, it is commonly used out of the box for local system mail and outbound relay on countless Linux servers.$q$, $q$Linux system administrators and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$University and institutional email systems$q$, $q$Originally built for the University of Cambridge Computing Service, Exim remains in use at UK academic institutions and other organizations that need a highly configurable, self-hosted mail gateway.$q$, $q$University IT departments and enterprise mail administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$Open Source$q$, $q$Free$q$, $q$N/A - perpetual free license (GPL-2.0-or-later)$q$, NULL, $q$["Full source code and binaries free to download, use, modify, and redistribute","No licensing fees, subscriptions, or paid tiers","ACL, router, transport, and content-scanning configuration included","TLS, DKIM, DMARC, ARC, and DANE support included","Community support via mailing lists, wiki, and public bug tracker","Regular security and feature releases from the volunteer maintainer team"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Exim is a free, open-source mail transfer agent (MTA) that runs on Unix-like operating systems, handling the routing, filtering, and delivery of email between servers. It was created in 1995 by Philip Hazel at the University of Cambridge Computing Service as a more flexible successor to the older Smail-3 mailer, and it is distributed under the GNU General Public License (GPL-2.0-or-later).$q$, $q$Rather than being a consumer-facing app, Exim operates behind the scenes: it is the software that shared-hosting control panels, ISPs, and Linux distributions rely on to actually send and receive SMTP mail. It is the default MTA on Debian Linux and is bundled with cPanel/WHM, one of the most widely used hosting control panels in the world.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Exim's configuration is split into access control lists (ACLs), routers, transports, retry rules, rewrite rules, and authenticators, giving administrators granular control over exactly how each message is accepted, routed, and delivered. A built-in string-expansion language lets policy logic be expressed directly in the configuration file, and a content-scanning framework allows easy integration with antivirus and antispam engines such as ClamAV and SpamAssassin.$q$, $q$It supports modern email authentication and encryption standards including TLS, SMTP AUTH, DKIM, DMARC, ARC, and DANE, and offers extensibility through a local_scan() C API and embedded Perl support for custom logic beyond what the configuration language alone can express.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Exim is completely free and has no paid tiers, subscriptions, or licensed editions; the GPL license guarantees the source code and binaries remain free to use, modify, and redistribute indefinitely. There is no vendor entity selling Exim, so there are no official support contracts - organizations that want commercial-grade help typically hire independent consultancies, some staffed by long-time Exim maintainers, rather than paying a central company.$q$, $q$Project infrastructure such as hosting and continuous integration is covered by volunteer sponsor organizations (for example Mythic Beasts, MacStadium, and Schlittermann) rather than by product revenue, which is typical for community-governed open-source infrastructure projects of this kind.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5b0bebc-38eb-4762-ae9c-52a84181c2e6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$SmartScan Receipt Capture$q$, $q$OCR-based technology that automatically extracts merchant, date, amount and category data from a photographed or emailed receipt, eliminating manual entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Automated Expense Reports$q$, $q$Expenses from receipts, mileage tracking and imported card feeds are compiled into expense reports that can be submitted with a few taps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Multi-Level Approval Workflows$q$, $q$Configurable approval chains route expense reports to the correct managers based on amount, category or department before reimbursement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Expensify Card$q$, $q$A corporate charge card offering up to 2 percent cash back at high spend volumes, real-time category spending controls, and instant freeze/unfreeze from the app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Expensify Travel$q$, $q$Built-in booking for flights, hotels, cars and rail, with a consolidated travel billing option that puts all employee trip charges on one monthly company statement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Bill Pay$q$, $q$Extends Expensify's approval and payment infrastructure to vendor invoices and accounts payable, alongside employee expense reimbursement.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Accounting and ERP Integrations$q$, $q$Two-way sync with QuickBooks Online and Desktop, Xero, NetSuite, Sage Intacct and FinancialForce to keep chart-of-accounts and vendor data current.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Policy Enforcement Rules$q$, $q$Custom expense rules and per diem or category limits flag non-compliant spending automatically before a report reaches an approver.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Genuinely free tier for individuals with 25 SmartScans per month and no team features required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Long track record as the pioneer of automated receipt scanning, with a mature and reliable OCR engine$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Simpler interface and setup than legacy enterprise tools like SAP Concur$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Bundled corporate card, travel booking and bill pay reduce the need for separate point solutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Collect plan charges per member added to a workspace regardless of whether that member submits expenses that month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Control plan's full feature set (SSO, payroll integrations, custom rules) requires the higher-priced annual commitment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Stock price has declined substantially since its 2021 IPO, reflecting increased competition from card-led spend platforms like Ramp and Brex$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Advanced compliance and enterprise integrations are gated behind the Control tier, which can be costly for larger teams without the Expensify Card$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Is Expensify free to use?$q$, $q$Yes, individuals can use Expensify for free with up to 25 SmartScans per month, unlimited manual expense entry and CSV export. Team workspaces require the paid Collect or Control plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$How much does Expensify cost for a business?$q$, $q$The Collect plan costs a flat 5 dollars per member per month with no annual commitment. The Control plan starts at 9 dollars per active member per month with an annual commitment and the Expensify Card, 18 dollars per member per month annually without the card, or 36 dollars per member per month with no commitment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$When was Expensify founded and by whom?$q$, $q$Expensify was founded in 2008 by David Barrett, who first presented the concept at TechCrunch50 before building out the company's receipt-scanning technology.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Is Expensify a public company?$q$, $q$Yes. Expensify went public on the Nasdaq Global Select Market in November 2021 under the ticker symbol EXFY, pricing its IPO at 27 dollars per share.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$What is the Expensify Card?$q$, $q$The Expensify Card is a corporate charge card that offers cash-back rewards, real-time category spending controls and the ability for administrators to freeze or unfreeze cards instantly from the app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$What accounting software does Expensify integrate with?$q$, $q$Expensify integrates with QuickBooks Online and Desktop, Xero, NetSuite, Sage Intacct and FinancialForce, syncing expense data directly into a company's existing accounting system.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Freelancer and sole proprietor expense tracking$q$, $q$Individuals use the free Expensify tier to photograph receipts, automatically extract expense data and export records for tax filing without needing a paid team plan.$q$, $q$Freelancers and sole proprietors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Small business expense approval and reimbursement$q$, $q$Small teams use the Collect plan to give employees a simple way to submit receipts, route them through basic approval workflows and get reimbursed without heavy IT setup.$q$, $q$Small business finance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Enterprise-grade spend control and compliance$q$, $q$Larger organizations use the Control plan's multi-level approvals, ERP and payroll integrations, custom policy rules and SSO to manage spend across departments while meeting compliance requirements.$q$, $q$Mid-market and enterprise finance and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Free (Individual)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 25 SmartScans per month","Unlimited manual expense entry","Distance and mileage tracking","CSV and spreadsheet export"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Collect$q$, $q$$5 per member per month$q$, $q$Monthly, no annual commitment$q$, NULL, $q$["Team workspaces with approval workflows","Reimbursement via direct deposit","Basic reporting","Expensify Card compatibility"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Control (Annual with Card)$q$, $q$$9 per active member per month$q$, $q$Annual commitment, requires Expensify Card usage$q$, NULL, $q$["Multi-level approval workflows","ERP integrations (NetSuite, Sage Intacct, FinancialForce)","HR and payroll integrations","Custom expense policy rules","SAML/SSO"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Control (Annual, no Card)$q$, $q$$18 per member per month$q$, $q$Annual commitment$q$, NULL, $q$["All Control features","No requirement to use the Expensify Card"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Control (Pay-Per-Use)$q$, $q$$36 per member per month$q$, $q$Month-to-month, no annual commitment$q$, NULL, $q$["All Control features","Pay only for active members each billing period"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Expensify is an expense management platform founded in 2008 by David Barrett and headquartered in Portland, Oregon. The company built its reputation on SmartScan, an early receipt-scanning technology that uses OCR to automatically extract merchant, date and amount data from photographed receipts, eliminating manual data entry from the expense reporting process.$q$, $q$Beyond expense reports, Expensify now offers a broader spend management suite that includes the Expensify Card (a corporate charge card with cash-back rewards and spending controls), Expensify Travel (flight, hotel, car and rail booking with consolidated monthly billing) and Bill Pay for vendor invoices. The company went public on the Nasdaq Global Select Market in November 2021 under the ticker EXFY.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of the product is automated receipt capture: employees can photograph receipts in the mobile app, forward emailed receipts to a dedicated inbox, or sync a bank or card feed so transactions import automatically, with SmartScan extracting the data needed to build an expense line item.$q$, $q$Configurable, multi-level approval workflows route submitted reports to the right managers, expense policy rules flag out-of-policy spending before submission, and integrated reimbursement can deposit funds into an employee's bank account within one to two business days. Accounting integrations with QuickBooks, Xero, NetSuite, Sage Intacct and FinancialForce keep finance systems in sync without manual re-entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Individuals can use Expensify for free, with up to 25 SmartScans per month, unlimited manual entry and CSV export, making it a viable option for freelancers and sole proprietors who do not need team workflows.$q$, $q$For company workspaces, Expensify restructured pricing in April 2025 around two tiers: Collect at a flat 5 dollars per member per month with no annual commitment, and Control (which adds multi-level approvals, ERP and payroll integrations, custom rules and SSO) starting at 9 dollars per active member per month with an annual commitment and the Expensify Card, rising to 18 dollars per member per month annually without the card, or 36 dollars per member per month on a no-commitment, pay-per-use basis.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
